input.command:
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:admin123password@localhost:27017/admin" --eval '
var appdb = db.getSiblingDB("appdb");
// 1. custom role reportingRole: read access to appdb.reports
appdb.createRole({
  role: "reportingRole",
  privileges: [
    { resource: { db: "appdb", collection: "reports" }, actions: [ "find", "listIndexes", "listCollections" ] }
  ],
  roles: []
});
// 2. app-user -> readWrite on appdb
appdb.getSiblingDB("admin").updateUser("app-user", { roles: [ { role: "readWrite", db: "appdb" } ] });
// 3. readonly-user -> read on appdb + reportingRole
appdb.getSiblingDB("admin").updateUser("readonly-user", { roles: [ { role: "read", db: "appdb" }, { role: "reportingRole", db: "appdb" } ] });
print("DONE");
' 2>&1

